function calculate({ annualDirectMedicalCosts, annualAppointments, averageTravelDistance, transportationCostPerMile, patientHourlyWage, averageAppointmentDurationHours, supportPersonsNeeded, supportPersonHourlyWage, childcareElderlyCareCostPerAppointment, annualOtherSupportCosts }) {

  // Ensure no negative inputs for calculation safety
  annualDirectMedicalCosts = Math.max(0, annualDirectMedicalCosts);
  annualAppointments = Math.max(0, annualAppointments);
  averageTravelDistance = Math.max(0, averageTravelDistance);
  transportationCostPerMile = Math.max(0, transportationCostPerMile);
  patientHourlyWage = Math.max(0, patientHourlyWage);
  averageAppointmentDurationHours = Math.max(0, averageAppointmentDurationHours);
  supportPersonsNeeded = Math.max(0, supportPersonsNeeded);
  supportPersonHourlyWage = Math.max(0, supportPersonHourlyWage);
  childcareElderlyCareCostPerAppointment = Math.max(0, childcareElderlyCareCostPerAppointment);
  annualOtherSupportCosts = Math.max(0, annualOtherSupportCosts);

  // 1. Calculate Total Direct Medical Costs
  const totalDirectMedicalCosts = annualDirectMedicalCosts;

  // 2. Calculate Total Transportation Costs
  const totalTravelMiles = annualAppointments * averageTravelDistance * 2; // Round trip
  const totalTransportationCosts = totalTravelMiles * transportationCostPerMile;

  // 3. Calculate Total Lost Wages (Patient)
  const totalHoursLostPatient = annualAppointments * averageAppointmentDurationHours;
  const totalLostWagesPatient = totalHoursLostPatient * patientHourlyWage;

  // 4. Calculate Total Lost Wages (Support Persons)
  const totalHoursLostSupport = annualAppointments * averageAppointmentDurationHours * supportPersonsNeeded;
  const totalLostWagesSupport = totalHoursLostSupport * supportPersonHourlyWage;

  // 5. Calculate Total Childcare/Elderly Care Costs
  const totalChildElderlyCareCosts = annualAppointments * childcareElderlyCareCostPerAppointment;

  // 6. Calculate Total Other Essential Support Costs (already annual)
  const totalOtherSupportCosts = annualOtherSupportCosts;

  // 7. Calculate Grand Total Burden
  const grandTotalBurden = 
    totalDirectMedicalCosts +
    totalTransportationCosts +
    totalLostWagesPatient +
    totalLostWagesSupport +
    totalChildElderlyCareCosts +
    totalOtherSupportCosts;

  return {
    totalDirectMedicalCosts,
    totalTransportationCosts,
    totalLostWagesPatient,
    totalLostWagesSupport,
    totalChildElderlyCareCosts,
    totalOtherSupportCosts,
    grandTotalBurden
  };
}
